let raw = $json.output;
let parsed = {};

try {
  parsed = JSON.parse(raw);
} catch (e) {
  parsed = {
    risks: [],
    growth_outlook: ""
  };
}

return [
  {
    json: parsed
  }
];

const {
  strengths = [],
  weaknesses = [],
  opportunities = [],
  threats = [],
  risks = [],
  growth_outlook = ""
} = $json;

// Helper to render bullet lists
const renderList = (items) =>
  items.map(item => `<li>${item}</li>`).join("");

// Build HTML report
const html = `
<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8" />
  <style>
    body {
      font-family: Arial, sans-serif;
      line-height: 1.6;
      color: #222;
      padding: 24px;
    }
    h1 {
      color: #0b5ed7;
      border-bottom: 2px solid #eee;
      padding-bottom: 8px;
    }
    h2 {
      color: #333;
      margin-top: 24px;
    }
    ul {
      margin-left: 20px;
    }
    li {
      margin-bottom: 6px;
    }
    .section {
      margin-bottom: 24px;
    }
  </style>
</head>
<body>

<h1>AI-Generated Equity Research Report</h1>

<div class="company">
<h2> Symbol : </h2><span>${ $('Iterate Companies').item.json.ticker }</span>
</div>

<div class="section">
  <h2>Strengths</h2>
  <ul>${renderList(strengths)}</ul>
</div>

<div class="section">
  <h2>Weaknesses</h2>
  <ul>${renderList(weaknesses)}</ul>
</div>

<div class="section">
  <h2>Opportunities</h2>
  <ul>${renderList(opportunities)}</ul>
</div>

<div class="section">
  <h2>Threats</h2>
  <ul>${renderList(threats)}</ul>
</div>

<div class="section">
  <h2>Key Risks</h2>
  <ul>${renderList(risks)}</ul>
</div>

<div class="section">
  <h2>Growth Outlook (12–24 Months)</h2>
  <p>${growth_outlook}</p>
</div>

</body>
</html>
`;

return [
  {
    json: {
      report_html: html
    }
  }
];

const items = $input.all();

const normalized = items.slice(0, 5).map(item => {
  const s = item.json;
  return {
    fiscal_year: s.fiscalYear,
    revenue: s.revenue,
    gross_profit: s.grossProfit,
    operating_income: s.operatingIncome,
    ebitda: s.ebitda,
    net_income: s.netIncome,
    eps_diluted: s.epsDiluted
  };
});

return [
  {
    json: {
      income_statement: normalized
    }
  }
];

const items = $input.all();

const normalized = items.slice(0, 5).map(item => {
  const s = item.json;
  return {
    fiscal_year: s.fiscalYear,
    assets: {
      cash_and_equivalents: s.cashAndCashEquivalents,
      total_current_assets: s.totalCurrentAssets,
      total_assets: s.totalAssets
    },
    liabilities: {
      total_current_liabilities: s.totalCurrentLiabilities,
      short_term_debt: s.shortTermDebt,
      long_term_debt: s.longTermDebt,
      total_liabilities: s.totalLiabilities
    },
    debt: {
      total_debt: s.totalDebt,
      net_debt: s.netDebt
    },
    equity: {
      total_equity: s.totalEquity
    }
  };
});

return [
  {
    json: {
      balance_sheet: normalized
    }
  }
];

const items = $input.all();

const normalized = items.slice(0, 5).map(item => {
  const s = item.json;
  return {
    fiscal_year: s.fiscalYear,
    cash_generation: {
      operating_cash_flow: s.operatingCashFlow,
      free_cash_flow: s.freeCashFlow,
      capital_expenditure: s.capitalExpenditure
    },
    earnings_to_cash: {
      net_income: s.netIncome,
      depreciation_and_amortization: s.depreciationAndAmortization,
      change_in_working_capital: s.changeInWorkingCapital
    },
    capital_allocation: {
      dividends_paid: s.netDividendsPaid,
      stock_repurchased: s.commonStockRepurchased,
      net_debt_issuance: s.netDebtIssuance
    }
  };
});

return [
  {
    json: {
      cash_flow: normalized
    }
  }
];

// NewsAPI response structure: { status, totalResults, articles }
const articles = $json.articles || [];

// Normalize and limit articles
const normalized = articles.slice(0, 5).map(a => ({
  title: a.title,
  summary: a.description,
  source: a.source?.name || null,
  published_at: a.publishedAt,
  url: a.url
}));

return {
  news: normalized
};

const data = $json;

const income = data.income_statement;
const balance = data.balance_sheet;
const cash = data.cash_flow;

// Latest vs oldest for trends
const latestIncome = income[0];
const oldestIncome = income[income.length - 1];

const revenueGrowth =
  (latestIncome.revenue - oldestIncome.revenue) / oldestIncome.revenue;

const margin =
  latestIncome.operating_income / latestIncome.revenue;

const latestBalance = balance[0];
const debtToEquity =
  latestBalance.debt.total_debt / latestBalance.equity.total_equity;

const latestCash = cash[0];
const fcfMargin =
  latestCash.cash_generation.free_cash_flow / latestIncome.revenue;

return {
  swot_signals: {
    revenue_growth_5y: revenueGrowth,
    operating_margin: margin,
    debt_to_equity: debtToEquity,
    fcf_margin: fcfMargin,
    stock_buybacks: latestCash.capital_allocation.stock_repurchased,
    news : data.news,
    news_count: data.news.length
  },
  original_data: data
};

let raw = $json.output;
let parsed = {};

try {
  parsed = JSON.parse(raw);
} catch (e) {
  parsed = {
    strengths: [],
    weaknesses: [],
    opportunities: [],
    threats: []
  };
}

return [
  {
    json: parsed
  }
];
